.order-summary-total {
    display: flex;
    justify-content: space-between;
    font-weight: 700;
    font-size: 16px;
}

/* ==========================================================================
   Phase 3: Dark Theme & UX Additions
   ========================================================================== */

body.dark-theme {
    --bg-primary: #0C0C0C;
    --bg-card: #161616;
    --text-primary: #FAF9F6;
    --text-muted: #A0A0A0;
    --border-color: #2D2D2D;
}

body.dark-theme .site-header {
    background-color: rgba(12, 12, 12, 0.85);
}

body.dark-theme .checkout-modal {
    background-color: var(--bg-card);
}

body.dark-theme .order-summary-box {
    background-color: var(--bg-primary);
}

body.dark-theme .cart-drawer {
    background-color: var(--bg-card);
    box-shadow: -10px 0 30px rgba(0, 0, 0, 0.3);
}

body.dark-theme .cart-footer {
    background-color: var(--bg-card);
}

body.dark-theme .cart-item-image {
    background: linear-gradient(135deg, #2D2D2D, #161616);
}

body.dark-theme .faq-item {
    background-color: var(--bg-card);
}

body.dark-theme .preset-btn {
    background-color: var(--bg-card);
    color: var(--text-primary);
}

body.dark-theme .preset-btn.active, 
body.dark-theme .preset-btn:hover {
    background-color: var(--text-primary);
    color: var(--bg-primary);
    border-color: var(--text-primary);
}

body.dark-theme .select-custom, 
body.dark-theme input {
    background-color: var(--bg-card);
    color: var(--text-primary);
}

body.dark-theme .contact-form-card {
    background-color: var(--bg-card);
}

body.dark-theme .science-chart-wrapper {
    background-color: var(--bg-card);
}

body.dark-theme .gallery-main {
    background-color: var(--bg-card);
}

body.dark-theme .btn-secondary {
    border-color: var(--text-primary);
    color: var(--text-primary);
}

body.dark-theme .btn-secondary:hover {
    background-color: var(--text-primary);
    color: var(--bg-card);
}

/* Toast Notifications */
.toast-container {
    position: fixed;
    bottom: 24px;
    right: 24px;
    z-index: 1000;
    display: flex;
    flex-direction: column;
    gap: 12px;
    pointer-events: none;
}

.toast-message {
    background-color: var(--text-primary);
    color: var(--bg-card);
    padding: 14px 24px;
    border-radius: 12px;
    font-size: 13px;
    font-weight: 600;
    box-shadow: 0 10px 30px rgba(0, 0, 0, 0.15);
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 20px;
    min-width: 300px;
    pointer-events: auto;
    opacity: 0;
    transform: translateY(20px);
    transition: opacity 0.3s ease, transform 0.3s cubic-bezier(0.16, 1, 0.3, 1);
}

.toast-message.show {
    opacity: 1;
    transform: translateY(0);
}

.toast-action {
    color: var(--color-sunrise);
    text-transform: uppercase;
    font-size: 11px;
    font-weight: 700;
    letter-spacing: 0.05em;
    cursor: pointer;
}

/* Header Currency & Theme buttons style adjustments */
.currency-selector-nav {
    font-size: 12px;
    font-weight: 700;
    padding: 6px 10px;
    border: 1px solid var(--border-color);
    border-radius: 20px;
    cursor: pointer;
    background-color: transparent;
    color: var(--text-primary);
    transition: var(--transition-fast);
}
.currency-selector-nav:hover {
    border-color: var(--text-primary);
}

.theme-toggle-nav {
    display: flex;
    align-items: center;
    justify-content: center;
    width: 34px;
    height: 34px;
    border-radius: 50%;
    border: 1px solid var(--border-color);
    cursor: pointer;
    background-color: transparent;
    color: var(--text-primary);
    transition: var(--transition-fast);
}
.theme-toggle-nav:hover {
    border-color: var(--text-primary);
}

/* Print Media Overrides for PDF plans */
@media print {
    body {
        background-color: #FFFFFF !important;
        color: #000000 !important;
    }
    .site-header, .site-footer, .calc-sidebar, #welcomeState, .recommended-products-box, .notes-box, #btnBuyBundle {
        display: none !important;
    }
    .container {
        padding: 0 !important;
        max-width: 100% !important;
    }
    .calc-layout {
        display: block !important;
    }
    .calc-results {
        border: none !important;
        padding: 0 !important;
        box-shadow: none !important;
    }
    .timeline {
        border-left-color: #000000 !important;
    }
    .timeline-dot {
        border-color: #FFFFFF !important;
        background-color: #000000 !important;
    }
    .timeline-content {
        background-color: #F0F0F0 !important;
        color: #000000 !important;
        border: 1px solid #CCCCCC !important;
    }
    .timeline-product-tag {
        border: 1px solid #000000 !important;
        color: #000000 !important;
        background-color: transparent !important;
    }
}

