105:         // 3.2 Calculations
106:         
107:         // Duration in decimal minutes
108:         const durationMinutes = distance * pace;
109:         const durationHours = durationMinutes / 60;
110:         
111:         // Formatted Duration Time String (H:MM:SS)
112:         const totalSecs = Math.round(durationMinutes * 60);
113:         const hoursPart = Math.floor(totalSecs / 3600);
114:         const minsPart = Math.floor((totalSecs % 3600) / 60);
115:         const secsPart = totalSecs % 60;
116:         const formattedDuration = `${hoursPart}:${minsPart.toString().padStart(2, '0')}:${secsPart.toString().padStart(2, '0')}`;
117:         
118:         // Target Carbohydrates per Hour
119:         let carbRatePerHour = 60; // Base default (grams/hr)
120:         
121:         if (durationHours < 1.0) {
