135:             carbRatePerHour = Math.min(100, carbRatePerHour + 10);
136:         }
137:         
138:         // Total carbohydrate requirement during the run
139:         const totalCarbsRequired = Math.round(carbRatePerHour * durationHours);
140:         
141:         // Fluid requirements (ml/hour)
